  }

  // 9. Kırılım analizi
  const breakout = checkBreakout(prices);
  if (breakout.score !== 0) {
    score += breakout.score;
    if (breakout.score > 0) signals.push('✅ ' + breakout.name);else warns.push('⚠️ ' + breakout.name);
