  // Başarı oranı — skor ne kadar yüksekse o kadar güvenilir
  const absScore = Math.abs(score);
  const successRate = Math.min(93, Math.max(53, 58 + absScore * 2.2 + (botId === 'hybrid' ? 4 : 0)));

  // Sinyal tipi
