    type = 'SAT';
    icon = '📉';
    cls = 'sell';
  } else if (score <= -5) {
    type = 'ZAYIF SAT';
    icon = '🔽';
    cls = 'sell';
  } else {
    type = 'BEKLE';
    icon = '⏸';
    cls = 'hold';
  }
  const reason = [...signals, ...warns].join('\n');
  return {
