// ─── AI SINYAL ENGİNE ────────────────────────────────────────────────────────
// Çoklu indikatör + ağırlıklı skor + trend analizi + hacim doğrulama

import { calcRSI, calcEMA, calcMACD, calcBollinger, calcStochRSI, calcATR } from './cryptoService';

// ── Trend gücü hesapla ─────────────────────────────────────────────────────
function calcTrendStrength(prices) {
  if (prices.length < 20) return 0;
  const last20  = prices.slice(-20);
  const first10 = last20.slice(0, 10);
  const last10  = last20.slice(10);
  const avg1    = first10.reduce((a, b) => a + b, 0) / 10;
  const avg2    = last10.reduce((a, b)  => a + b, 0) / 10;
  return parseFloat(((avg2 - avg1) / avg1 * 100).toFixed(3));
}

// ── Momentum hesapla ───────────────────────────────────────────────────────
function calcMomentum(prices, period = 10) {
  if (prices.length < period) return 0;
  const current = prices[prices.length - 1];
  const past    = prices[prices.length - period];
  return parseFloat(((current - past) / past * 100).toFixed(3));
}

// ── Hareketli ortalama sapması ─────────────────────────────────────────────
function calcPriceVsEMA(prices, period) {
  const ema   = calcEMA(prices, Math.min(period, prices.length));
  const price = prices[prices.length - 1];
  return parseFloat(((price - ema) / ema * 100).toFixed(3));
}

// ── Volatilite skoru ───────────────────────────────────────────────────────
function calcVolatilityScore(prices) {
  if (prices.length < 14) return 50;
  const atr   = calcATR(prices);
  const price = prices[prices.length - 1];
  return parseFloat((atr / price * 100).toFixed(3));
}

// ── Fiyat paterni tespiti ──────────────────────────────────────────────────
function detectPattern(prices) {
  if (prices.length < 5) return { name: 'Yok', score: 0 };
  const last5 = prices.slice(-5);
  const [p1, p2, p3, p4, p5] = last5;

  // Çift dip (Double Bottom) — güçlü al sinyali
  if (p1 > p2 && p2 < p3 && p3 > p4 && p4 < p5 && Math.abs(p2 - p4) / p2 < 0.02) {
    return { name: 'Çift Dip 📊', score: 4, type: 'buy' };
  }
  // Çift zirve (Double Top) — güçlü sat sinyali
  if (p1 < p2 && p2 > p3 && p3 < p4 && p4 > p5 && Math.abs(p2 - p4) / p2 < 0.02) {
    return { name: 'Çift Zirve 📊', score: -4, type: 'sell' };
  }
  // Yükselen üçgen — al sinyali
  if (p5 > p3 && p3 > p1 && Math.abs(p2 - p4) / p2 < 0.01) {
    return { name: 'Yükselen Üçgen 📐', score: 3, type: 'buy' };
  }
  // Alçalan üçgen — sat sinyali
  if (p5 < p3 && p3 < p1 && Math.abs(p2 - p4) / p2 < 0.01) {
    return { name: 'Alçalan Üçgen 📐', score: -3, type: 'sell' };
  }
  // Güçlü yükseliş
  if (p5 > p4 && p4 > p3 && p3 > p2 && p2 > p1) {
    return { name: 'Güçlü Yükseliş 📈', score: 2, type: 'buy' };
  }
  // Güçlü düşüş
  if (p5 < p4 && p4 < p3 && p3 < p2 && p2 < p1) {
    return { name: 'Güçlü Düşüş 📉', score: -2, type: 'sell' };
  }

  return { name: 'Belirsiz', score: 0 };
}

// ── Destek/Direnç kırılımı ─────────────────────────────────────────────────
function checkBreakout(prices) {
  if (prices.length < 20) return { breakout: false, score: 0 };
  const recent   = prices.slice(-20);
  const high20   = Math.max(...recent.slice(0, 19));
  const low20    = Math.min(...recent.slice(0, 19));
  const lastPrice = prices[prices.length - 1];
  const prevPrice = prices[prices.length - 2];

  if (lastPrice > high20 && prevPrice <= high20) {
    return { breakout: true, type: 'up',   score: 5, name: 'Direnç Kırıldı ⚡' };
  }
  if (lastPrice < low20 && prevPrice >= low20) {
    return { breakout: true, type: 'down', score: -5, name: 'Destek Kırıldı ⚡' };
  }
  return { breakout: false, score: 0 };
}

// ── RSI Diverjansı ─────────────────────────────────────────────────────────
function checkDivergence(prices) {
  if (prices.length < 30) return { score: 0 };
  const recentPrices = prices.slice(-30);
  const midIdx = 15;

  const price1 = recentPrices[midIdx];
  const price2 = recentPrices[recentPrices.length - 1];
  const rsi1   = calcRSI(recentPrices.slice(0, midIdx + 1));
  const rsi2   = calcRSI(recentPrices);

  // Boğa diverjansı: fiyat düşüyor ama RSI yükseliyor
  if (price2 < price1 && rsi2 > rsi1 && rsi2 < 50) {
    return { score: 4, name: 'Boğa Diverjansı 🔄', type: 'buy' };
  }
  // Ayı diverjansı: fiyat yükseliyor ama RSI düşüyor
  if (price2 > price1 && rsi2 < rsi1 && rsi2 > 50) {
    return { score: -4, name: 'Ayı Diverjansı 🔄', type: 'sell' };
  }
  return { score: 0 };
}

// ── ANA AI SİNYAL FONKSİYONU ──────────────────────────────────────────────
export function aiGenerateSignal(prices, botId = 'hybrid') {
  if (!prices || prices.length < 30) {
    return {
      type: 'BEKLE', icon: '⏸', cls: 'hold',
      score: 0, successRate: 50, reason: 'Yeterli veri yok',
      details: {}
    };
  }

  let score = 0;
  const signals = [];
  const warns   = [];

  // 1. RSI analizi
  const rsi = calcRSI(prices);
  if (rsi <= 20)      { score += 5; signals.push('✅ RSI aşırı satım (' + rsi + ') — güçlü dip'); }
  else if (rsi <= 30) { score += 4; signals.push('✅ RSI satım bölgesi (' + rsi + ')'); }
  else if (rsi <= 40) { score += 2; signals.push('✅ RSI düşük (' + rsi + ')'); }
  else if (rsi >= 80) { score -= 5; warns.push('⚠️ RSI aşırı alım (' + rsi + ') — güçlü zirve'); }
  else if (rsi >= 70) { score -= 4; warns.push('⚠️ RSI alım bölgesi (' + rsi + ')'); }
  else if (rsi >= 60) { score -= 2; warns.push('⚠️ RSI yüksek (' + rsi + ')'); }

  // 2. Stochastic RSI
  const stochRSI = calcStochRSI(prices);
  if (stochRSI <= 15)      { score += 4; signals.push('✅ StochRSI aşırı satım (' + stochRSI + ')'); }
  else if (stochRSI <= 25) { score += 2; signals.push('✅ StochRSI düşük (' + stochRSI + ')'); }
  else if (stochRSI >= 85) { score -= 4; warns.push('⚠️ StochRSI aşırı alım (' + stochRSI + ')'); }
  else if (stochRSI >= 75) { score -= 2; warns.push('⚠️ StochRSI yüksek (' + stochRSI + ')'); }

  // 3. MACD
  const macd = calcMACD(prices);
  if (macd > 200)       { score += 5; signals.push('✅ MACD güçlü pozitif (+' + macd + ')'); }
  else if (macd > 50)   { score += 3; signals.push('✅ MACD pozitif (+' + macd + ')'); }
  else if (macd > 0)    { score += 1; signals.push('✅ MACD hafif pozitif'); }
  else if (macd < -200) { score -= 5; warns.push('⚠️ MACD güçlü negatif (' + macd + ')'); }
  else if (macd < -50)  { score -= 3; warns.push('⚠️ MACD negatif (' + macd + ')'); }
  else if (macd < 0)    { score -= 1; warns.push('⚠️ MACD hafif negatif'); }

  // 4. EMA Cross
  const ema20  = calcEMA(prices, Math.min(20, prices.length));
  const ema50  = calcEMA(prices, Math.min(50, prices.length));
  const ema200 = calcEMA(prices, Math.min(200, prices.length));
  if (ema20 > ema50 && ema50 > ema200) {
    score += 4; signals.push('✅ EMA20 > EMA50 > EMA200 — güçlü yükseliş trendi');
  } else if (ema20 > ema50) {
    score += 2; signals.push('✅ EMA Golden Cross (20/50)');
  } else if (ema20 < ema50 && ema50 < ema200) {
    score -= 4; warns.push('⚠️ EMA20 < EMA50 < EMA200 — güçlü düşüş trendi');
  } else if (ema20 < ema50) {
    score -= 2; warns.push('⚠️ EMA Death Cross (20/50)');
  }

  // 5. Bollinger Bands
  const bbPos = calcBollinger(prices);
  if (bbPos <= 5)       { score += 4; signals.push('✅ Bollinger alt bant kırıldı — dip sinyali'); }
  else if (bbPos <= 20) { score += 2; signals.push('✅ Bollinger alt bant yakını (%' + bbPos + ')'); }
  else if (bbPos >= 95) { score -= 4; warns.push('⚠️ Bollinger üst bant kırıldı — zirve sinyali'); }
  else if (bbPos >= 80) { score -= 2; warns.push('⚠️ Bollinger üst bant yakını (%' + bbPos + ')'); }

  // 6. Trend gücü
  const trendStrength = calcTrendStrength(prices);
  if (trendStrength > 2)       { score += 3; signals.push('✅ Güçlü yükseliş trendi (%' + trendStrength + ')'); }
  else if (trendStrength > 0.5){ score += 1; signals.push('✅ Hafif yükseliş trendi'); }
  else if (trendStrength < -2) { score -= 3; warns.push('⚠️ Güçlü düşüş trendi (%' + trendStrength + ')'); }
  else if (trendStrength < -0.5){ score -= 1; warns.push('⚠️ Hafif düşüş trendi'); }

  // 7. Momentum
  const momentum = calcMomentum(prices);
  if (momentum > 3)       { score += 2; signals.push('✅ Güçlü pozitif momentum (%' + momentum + ')'); }
  else if (momentum > 1)  { score += 1; }
  else if (momentum < -3) { score -= 2; warns.push('⚠️ Güçlü negatif momentum (%' + momentum + ')'); }
  else if (momentum < -1) { score -= 1; }

  // 8. Fiyat paterni
  const pattern = detectPattern(prices);
  if (pattern.score !== 0) {
    score += pattern.score;
    if (pattern.score > 0) signals.push('✅ Patern: ' + pattern.name);
    else warns.push('⚠️ Patern: ' + pattern.name);
  }

  // 9. Kırılım analizi
  const breakout = checkBreakout(prices);
  if (breakout.score !== 0) {
    score += breakout.score;
    if (breakout.score > 0) signals.push('✅ ' + breakout.name);
    else warns.push('⚠️ ' + breakout.name);
  }

  // 10. RSI Diverjansı
  const divergence = checkDivergence(prices);
  if (divergence.score !== 0) {
    score += divergence.score;
    if (divergence.score > 0) signals.push('✅ ' + divergence.name);
    else warns.push('⚠️ ' + divergence.name);
  }

  // 11. Fiyat vs EMA pozisyonu
  const priceVsEMA50 = calcPriceVsEMA(prices, 50);
  if (priceVsEMA50 > 0 && priceVsEMA50 < 3)  { score += 1; signals.push('✅ Fiyat EMA50 üzerinde'); }
  if (priceVsEMA50 < 0 && priceVsEMA50 > -3) { score -= 1; warns.push('⚠️ Fiyat EMA50 altında'); }

  // Bot bonusu
  const botBonus = { trend: 2, rsi: 2, bb: 2, hybrid: 3 };
  score += (botBonus[botId] || 0);

  // Başarı oranı — skor ne kadar yüksekse o kadar güvenilir
  const absScore    = Math.abs(score);
  const successRate = Math.min(93, Math.max(53,
    58 + absScore * 2.2 + (botId === 'hybrid' ? 4 : 0)
  ));

  // Sinyal tipi
  let type, icon, cls;
  if (score >= 15)      { type = 'GÜÇLÜ AL';  icon = '🚀'; cls = 'buy'; }
  else if (score >= 10) { type = 'AL';         icon = '📈'; cls = 'buy'; }
  else if (score >= 5)  { type = 'ZAYIF AL';   icon = '🔼'; cls = 'buy'; }
  else if (score <= -15){ type = 'GÜÇLÜ SAT'; icon = '🔻'; cls = 'sell'; }
  else if (score <= -10){ type = 'SAT';        icon = '📉'; cls = 'sell'; }
  else if (score <= -5) { type = 'ZAYIF SAT';  icon = '🔽'; cls = 'sell'; }
  else                  { type = 'BEKLE';      icon = '⏸';  cls = 'hold'; }

  const reason = [...signals, ...warns].join('\n');

  return {
    type, icon, cls, score,
    successRate: Math.round(successRate),
    reason,
    details: {
      rsi, stochRSI, macd, bbPos, trendStrength,
      momentum, pattern: pattern.name,
      breakout: breakout.name || 'Yok',
      divergence: divergence.name || 'Yok',
      ema20, ema50, ema200,
    }
  };
}
